+    let input = make_hook_input("git status");
+    let (stdout, _stderr, exit_code) = run_hook_mode_raw(&input);
+
+    assert_eq!(exit_code, 0, "git status should exit 0");
+    assert!(stdout.trim().is_empty(), "git status should produce no stdout");
+}
+
